        pq.pop();
        long long current_min = current.min_cost;
        long long current_total = current.total_cost;
        int u = current.node;

        if (u == n - 1) {
            if (current_total <= k) {
                max_score = max(max_score, current_min);
            }
            continue;
        }

        for (const auto& neighbor : adj[u]) {
            int v = neighbor.first;
            long long cost = neighbor.second;

            if (!online[v] && v != n - 1) {
                continue;
